#include <stdio.h>
#include <yara.h>

int callback(int message, void* message_data, void* user_data) {
    if (message == CALLBACK_MSG_RULE_MATCHING) {
        printf("Rule matched!\n");
        (*(int*)user_data)++;
    }
    return CALLBACK_CONTINUE;
}

int test_rule(const char* rule_str, const uint8_t* blob, size_t len) {
    YR_COMPILER* compiler = NULL;
    YR_RULES* rules = NULL;

    yr_compiler_create(&compiler);

    if (yr_compiler_add_string(compiler, rule_str, NULL) != 0) {
        printf("Failed to compile rule: %s\n", compiler->last_error_msg);
        yr_compiler_destroy(compiler);
        return -1;
    }

    yr_compiler_get_rules(compiler, &rules);

    int matches = 0;
    yr_rules_scan_mem(rules, blob, len, 0, callback, &matches, 0);

    yr_rules_destroy(rules);
    yr_compiler_destroy(compiler);

    return matches;
}

int main() {
    yr_initialize();

    uint8_t blob[] = "abc\xE0\x22";
    size_t len = 5;

    printf("Blob: ");
    for (size_t i = 0; i < len; i++) {
        printf("%02x ", blob[i]);
    }
    printf("\n\n");

    printf("Test 1: /abc([^\"\\\\])*\"/ without nocase: ");
    printf("%d\n", test_rule("rule test { strings: $a =/abc([^\"\\\\])*\"/ condition: $a }", blob, len));

    printf("Test 2: /abc([^\"\\\\])*\"/ with nocase: ");
    printf("%d\n", test_rule("rule test { strings: $a =/abc([^\"\\\\])*\"/ nocase condition: $a }", blob, len));

    printf("Test 3: /abc[^\"\\\\]\"/ without nocase: ");
    printf("%d\n", test_rule("rule test { strings: $a =/abc[^\"\\\\]\"/ condition: $a }", blob, len));

    printf("Test 4: /abc[^\"\\\\]\"/ with nocase: ");
    printf("%d\n", test_rule("rule test { strings: $a =/abc[^\"\\\\]\"/ nocase condition: $a }", blob, len));

    yr_finalize();

    return 0;
}
